import respx from httpx import Response
@respx.mock async def test_fetch_user_from_external_api(): respx.get("https://api.example.com/users/1").mock( return_value=Response(200, json={"id": 1, "name": "Test User"}) )
result = await fetch_user(user_id=1)
assert result["name"] == "Test User" assert respx.calls.call_count == 1
@respx.mock async def test_handles_external_api_error(): respx.get("https://api.example.com/users/99").mock( return_value=Response(404) )
with pytest.raises(UserNotFoundError): await fetch_user(user_id=99)

import requests
from testcontainers.core.container import DockerContainer

@pytest.fixture(scope="session")
def wiremock_url():
    container = DockerContainer("wiremock/wiremock:3.3.1")
    container.with_exposed_ports(8080)
    container.start()
    url = f"http://{container.get_container_host_ip()}:{container.get_exposed_port(8080)}"
    yield url
    container.stop()

@pytest.fixture(autouse=True)
def clear_wiremock_mappings(wiremock_url):
    yield
    requests.delete(f"{wiremock_url}/__admin/mappings")

def stub_payment_success(wiremock_url: str):
    requests.post(f"{wiremock_url}/__admin/mappings", json={
        "request": {"method": "POST", "urlPath": "/charge"},
        "response": {
            "status": 200,
            "jsonBody": {"payment_id": "pay_123", "status": "success"},
        },
    })

def test_payment_flow(client, wiremock_url):
    stub_payment_success(wiremock_url)
    response = client.post("/api/orders/1/pay")
    assert response.status_code == 200
